+            try self.emit("@as(i64, @intFromBool(");
+            try genExpr(self, binop.left.*);
+            try self.emit("))");
+        } else {
+            try genExpr(self, binop.left.*);
+        }
+        try self.emit(", ");
+        if (right_type == .bool) {
+            try self.emit("@as(i64, @intFromBool(");
+            try genExpr(self, binop.right.*);
+            try self.emit("))");
+        } else {
+            try genExpr(self, binop.right.*);
+        }
+        try self.emit(")");
+        return;
+    }
